import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { decryptObject } from "@/lib/crypto";
import { createLicenseKeys } from "@/lib/license";
import { getAuthenticatedUser, getJson, rateLimit } from "@/lib/http";
import { z } from "zod";

const generateSchema = z.object({
  scriptId: z.string().uuid(),
  type: z.enum(["LIFETIME", "SUBSCRIPTION"]).optional().default("LIFETIME"),
  durationDays: z.number().int().min(1).max(3650).optional(),
  count: z.number().int().min(1).max(100),
  note: z.string().max(200).optional(),
  hwidLock: z.boolean().optional().default(true),
  groupId: z.string().uuid().optional().nullable(),
  tags: z.array(z.string().max(40)).max(20).optional(),
  trial: z.boolean().optional().default(false),
  productId: z.string().max(80).optional().nullable(),
  transferable: z.boolean().optional().default(true),
});

function sanitizeLicense(license: any) {
  let key = "";
  try {
    key = decryptObject<{ key: string }>(license.keyEncrypted).key;
  } catch {
    key = "";
  }

  return {
    ...license,
    key,
    keyEncrypted: undefined,
    keyHash: undefined,
  };
}

export async function GET(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`licenses:list:${user.id}`, 60, 60 * 1000);
  if (!limited.success)
    return NextResponse.json(
      { error: "Too many requests" },
      {
        status: 429,
        headers: { "X-RateLimit-Reset": limited.reset.toString() },
      },
    );

  const { searchParams } = new URL(req.url);
  const page = Math.max(Number(searchParams.get("page") || 1), 1);
  const take = Math.min(Number(searchParams.get("take") || 50), 100);
  const search = searchParams.get("search") || "";
  const status = searchParams.get("status") as any;

  const where: any =
    user.role === "ADMIN"
      ? {}
      : {
          OR: [
            { ownerId: user.id },
            { script: { team: { members: { some: { userId: user.id } } } } },
          ],
        };
  if (search) {
    where.OR = [
      { note: { contains: search, mode: "insensitive" } },
      { redeemedBy: { contains: search, mode: "insensitive" } },
    ];
  }
  if (status) where.status = status;

  const licenses = await db.license.findMany({
    where,
    include: {
      script: { select: { name: true } },
      owner: { select: { username: true } },
    },
    orderBy: { createdAt: "desc" },
    skip: (page - 1) * take,
    take,
  });

  return NextResponse.json({
    licenses: licenses.map(sanitizeLicense),
    page,
    take,
  });
}

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user || !["ADMIN", "DEVELOPER", "SELLER"].includes(user.role))
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`licenses:create:${user.id}`, 10, 60 * 1000);
  if (!limited.success)
    return NextResponse.json(
      { error: "Too many license generation attempts" },
      { status: 429 },
    );

  try {
    const body = generateSchema.safeParse(await getJson(req));
    if (!body.success)
      return NextResponse.json(
        {
          error: "Invalid license generation request",
          details: body.error.flatten(),
        },
        { status: 400 },
      );

    const script = await db.script.findUnique({
      where: { id: body.data.scriptId },
      select: { id: true, name: true },
    });
    if (!script)
      return NextResponse.json({ error: "Script not found" }, { status: 404 });

    const keys = await createLicenseKeys({
      scriptId: script.id,
      ownerId: user.id,
      type: body.data.type,
      durationDays: body.data.durationDays,
      count: body.data.count,
      note: body.data.note,
      hwidLock: body.data.hwidLock,
      groupId: body.data.groupId,
      tags: body.data.tags || undefined,
      trial: body.data.trial,
      productId: body.data.productId,
      transferable: body.data.transferable,
    });

    await createAuditLog(
      user.id,
      "LICENSE_CREATE_BULK",
      { count: body.data.count, scriptId: script.id, scriptName: script.name },
      undefined,
      req.headers.get("user-agent") || undefined,
      "License",
      script.id,
    );

    return NextResponse.json({
      message: `Successfully generated ${body.data.count} license keys`,
      keys,
    });
  } catch (error) {
    console.error("POST Licenses Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

"use client"

import React, { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  KeyRound,
  Plus,
  Trash2,
  RefreshCw,
  Search,
  Filter,
  CheckCircle,
  AlertOctagon,
  Eye,
  EyeOff,
  Clipboard,
  X,
  Lock,
  Unlock,
  CornerDownRight,
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

interface License {
  id: string;
  key: string;
  type: "LIFETIME" | "SUBSCRIPTION";
  status: "UNREDEEMED" | "ACTIVE" | "SUSPENDED" | "EXPIRED" | "BLACKLISTED";
  durationDays: number | null;
  expiresAt: string | null;
  redeemedAt: string | null;
  redeemedBy: string | null;
  note: string | null;
  hwidLock: boolean;
  hwidResetCount: number;
  hwidResetLimit: number;
  blacklistReason: string | null;
  tags?: string[];
  trial?: boolean;
  productId?: string | null;
  transferable?: boolean;
  script: { name: string };
  owner: { username: string };
}

interface Script {
  id: string;
  name: string;
}

export default function LicenseManager() {
  const [licenses, setLicenses] = useState<License[]>([]);
  const [scripts, setScripts] = useState<Script[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState("ALL");

  const [modalOpen, setModalOpen] = useState(false);

  // Key generation form states
  const [scriptId, setScriptId] = useState("");
  const [type, setType] = useState<"LIFETIME" | "SUBSCRIPTION">("LIFETIME");
  const [durationDays, setDurationDays] = useState("30");
  const [count, setCount] = useState("1");
  const [note, setNote] = useState("");
  const [hwidLock, setHwidLock] = useState(true);
  const [tags, setTags] = useState("");
  const [trial, setTrial] = useState(false);
  const [productId, setProductId] = useState("");
  const [transferable, setTransferable] = useState(true);
  const [keyPrefix, setKeyPrefix] = useState("LUA");

  // Newly generated keys display modal
  const [genModalOpen, setGenModalOpen] = useState(false);
  const [newlyGeneratedKeys, setNewlyGeneratedKeys] = useState<string[]>([]);

  async function fetchLicensesAndScripts() {
    try {
      setLoading(true);
      const [licensesRes, scriptsRes] = await Promise.all([
        fetch("/api/licenses"),
        fetch("/api/scripts"),
      ]);
      const licensesData = await licensesRes.json();
      const scriptsData = await scriptsRes.json();

      if (licensesData.licenses) setLicenses(licensesData.licenses);
      if (scriptsData.scripts) {
        setScripts(scriptsData.scripts);
        if (scriptsData.scripts.length > 0) {
          setScriptId(scriptsData.scripts[0].id);
        }
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    fetchLicensesAndScripts();
  }, []);

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch("/api/licenses", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          scriptId,
          type,
          durationDays,
          count,
          note,
          hwidLock,
          tags: tags.split(",").map((tag) => tag.trim()).filter(Boolean),
          trial,
          productId: productId || null,
          transferable,
          keyPrefix: keyPrefix || undefined,
        }),
      });

      const data = await res.json();
      if (res.ok && data.keys) {
        setNewlyGeneratedKeys(data.keys);
        setModalOpen(false);
        setGenModalOpen(true);
        fetchLicensesAndScripts();
        // Reset form
        setNote("");
        setCount("1");
        setTags("");
        setTrial(false);
        setProductId("");
        setTransferable(true);
        setKeyPrefix("LUA");
      } else {
        alert(data.error || "Failed to generate keys");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleResetHWID = async (licenseId: string) => {
    try {
      const res = await fetch(`/api/licenses/${licenseId}/reset-hwid`, {
        method: "POST",
      });
      const data = await res.json();
      if (res.ok) {
        alert(data.message);
        fetchLicensesAndScripts();
      } else {
        alert(data.error || "Failed to reset HWID");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleDelete = async (licenseId: string) => {
    if (!confirm("Are you sure you want to delete this license key?")) return;
    try {
      const res = await fetch(`/api/licenses/${licenseId}`, {
        method: "DELETE",
      });
      if (res.ok) {
        fetchLicensesAndScripts();
      } else {
        alert("Failed to delete license key");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleUpdateStatus = async (licenseId: string, currentStatus: string) => {
    const newStatus = currentStatus === "SUSPENDED" ? "ACTIVE" : "SUSPENDED";
    try {
      const res = await fetch(`/api/licenses/${licenseId}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status: newStatus }),
      });
      if (res.ok) {
        fetchLicensesAndScripts();
      } else {
        alert("Failed to update status");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleBlacklist = async (licenseId: string) => {
    const reason = window.prompt("Blacklist reason");
    if (reason === null) return;
    try {
      const res = await fetch(`/api/licenses/${licenseId}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status: "BLACKLISTED", blacklistReason: reason || "No reason provided" }),
      });
      if (res.ok) {
        fetchLicensesAndScripts();
      } else {
        alert("Failed to blacklist license");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleTransfer = async (licenseId: string) => {
    const email = window.prompt("Recipient email");
    if (!email) return;
    const res = await fetch(`/api/licenses/${licenseId}/transfer`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ toUserEmail: email }),
    });
    const data = await res.json();
    alert(data.message || data.error || "Transfer request created");
  };

  const handleRestore = async (licenseId: string) => {
    const reason = window.prompt("Restoration reason");
    if (!reason) return;
    const res = await fetch(`/api/licenses/${licenseId}/restore`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ reason }),
    });
    const data = await res.json();
    alert(data.message || data.error || "Restoration request created");
  };

  const handleHWIDResetRequest = async (licenseId: string) => {
    const reason = window.prompt("HWID reset reason");
    if (!reason) return;
    const res = await fetch(`/api/licenses/${licenseId}/hwid-reset-requests`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ reason }),
    });
    const data = await res.json();
    alert(data.message || data.error || "HWID reset request created");
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copied key to clipboard!");
  };

  const filteredLicenses = licenses.filter((lic) => {
    const matchesSearch =
      lic.key.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (lic.note && lic.note.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (lic.redeemedBy && lic.redeemedBy.toLowerCase().includes(searchTerm.toLowerCase()));
    const matchesFilter = filterStatus === "ALL" || lic.status === filterStatus;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-extrabold text-white tracking-tight glow-red">
            License Control
          </h1>
          <p className="text-gray-400 text-sm mt-1">
            Generate, reset machine locks, and revoke script authorization keys.
          </p>
        </div>
        <Button onClick={() => setModalOpen(true)} className="gap-2" variant="glow" disabled={scripts.length === 0}>
          <Plus className="h-4 w-4" /> Bulk Generate
        </Button>
      </div>

      {/* Filter and Search Bar */}
      <div className="flex flex-col md:flex-row gap-4 items-center justify-between bg-black/20 border border-white/5 p-4 rounded-xl">
        <div className="relative w-full md:w-80">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-gray-500" />
          <Input
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Search key, note, or redeemer..."
            className="pl-9"
          />
        </div>
        <div className="flex gap-2 items-center w-full md:w-auto">
          <Filter className="h-4 w-4 text-gray-400" />
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            className="flex h-10 rounded-lg border border-border/60 bg-black/40 px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-primary/50"
          >
            <option value="ALL" className="bg-[#0b0f19]">All Statuses</option>
            <option value="UNREDEEMED" className="bg-[#0b0f19]">Unredeemed</option>
            <option value="ACTIVE" className="bg-[#0b0f19]">Active</option>
            <option value="SUSPENDED" className="bg-[#0b0f19]">Suspended</option>
            <option value="EXPIRED" className="bg-[#0b0f19]">Expired</option>
            <option value="BLACKLISTED" className="bg-[#0b0f19]">Blacklisted</option>
          </select>
        </div>
      </div>

      {/* Main License List Table */}
      {loading ? (
        <div className="flex justify-center py-20">
          <RefreshCw className="h-10 w-10 text-red-500 animate-spin" />
        </div>
      ) : (
        <Card className="overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-left text-sm text-gray-300">
              <thead className="bg-white/[0.02] border-b border-white/5 text-gray-400 uppercase text-xs font-mono">
                <tr>
                  <th className="px-6 py-4">License Key</th>
                  <th className="px-6 py-4">Script Binding</th>
                  <th className="px-6 py-4">Type</th>
                  <th className="px-6 py-4">Tags</th>
                  <th className="px-6 py-4">Status</th>
                  <th className="px-6 py-4">User Binding</th>
                  <th className="px-6 py-4">Reset Count</th>
                  <th className="px-6 py-4">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {filteredLicenses.length === 0 ? (
                  <tr>
                    <td colSpan={8} className="text-center py-16 text-gray-500 font-medium">
                      No licenses found matching your current query.
                    </td>
                  </tr>
                ) : (
                  filteredLicenses.map((lic) => (
                    <tr key={lic.id} className="hover:bg-white/[0.01] transition-colors duration-200">
                      <td className="px-6 py-4 font-mono text-red-300 font-semibold flex items-center gap-2">
                        <span>{lic.key}</span>
                        <button onClick={() => copyToClipboard(lic.key)} className="text-gray-500 hover:text-white transition-colors">
                          <Clipboard className="h-3.5 w-3.5" />
                        </button>
                      </td>
                      <td className="px-6 py-4 font-medium text-white">{lic.script.name}</td>
                      <td className="px-6 py-4 text-xs font-mono uppercase">
                        {lic.type === "LIFETIME" ? (
                          <span className="text-red-400">Lifetime</span>
                        ) : (
                          <span className="text-amber-400">Sub ({lic.durationDays}d)</span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        {lic.tags && Array.isArray(lic.tags) && lic.tags.length > 0 ? (
                          <div className="flex flex-wrap gap-1">
                            {lic.tags.map((tag: string) => (
                              <span key={tag} className="text-[10px] text-red-300 bg-red-500/10 border border-red-500/20 px-2 py-0.5 rounded">
                                {tag}
                              </span>
                            ))}
                          </div>
                        ) : (
                          <span className="text-gray-500 italic">None</span>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        {lic.status === "ACTIVE" && (
                          <span className="bg-emerald-500/10 text-emerald-400 px-2.5 py-1 rounded text-xs font-semibold uppercase border border-emerald-500/20">
                            Active
                          </span>
                        )}
                        {lic.status === "UNREDEEMED" && (
                          <span className="bg-gray-500/10 text-gray-400 px-2.5 py-1 rounded text-xs font-semibold uppercase border border-white/5">
                            Unredeemed
                          </span>
                        )}
                        {lic.status === "SUSPENDED" && (
                          <span className="bg-red-500/10 text-red-400 px-2.5 py-1 rounded text-xs font-semibold uppercase border border-red-500/20 animate-pulse">
                            Suspended
                          </span>
                        )}
                        {lic.status === "EXPIRED" && (
                          <span className="bg-amber-500/10 text-amber-400 px-2.5 py-1 rounded text-xs font-semibold uppercase border border-amber-500/20">
                            Expired
                          </span>
                        )}
                        {lic.status === "BLACKLISTED" && (
                          <div className="space-y-1">
                            <span className="bg-red-950/40 text-red-300 px-2.5 py-1 rounded text-xs font-semibold uppercase border border-red-500/20">
                              Blacklisted
                            </span>
                            {lic.blacklistReason && <span className="block text-[10px] text-red-400 max-w-[180px] truncate">{lic.blacklistReason}</span>}
                          </div>
                        )}
                      </td>
                      <td className="px-6 py-4">
                        {lic.redeemedBy ? (
                          <div className="flex flex-col">
                            <span className="text-white font-semibold">{lic.redeemedBy}</span>
                            <span className="text-[10px] text-gray-500 font-mono">
                              {lic.expiresAt ? `Expires: ${new Date(lic.expiresAt).toLocaleDateString()}` : "No Expiration"}
                            </span>
                          </div>
                        ) : (
                          <span className="text-gray-500 italic">None</span>
                        )}
                      </td>
                      <td className="px-6 py-4 font-mono text-xs text-gray-400">
                        {lic.hwidResetCount} / {lic.hwidResetLimit}
                      </td>
                        <td className="px-6 py-4 flex items-center gap-2">
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleTransfer(lic.id)}
                            title="Request license transfer"
                            className="h-8 border-white/10"
                          >
                            Transfer
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleRestore(lic.id)}
                            title="Request license restoration"
                            className="h-8 border-white/10"
                          >
                            Restore
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleHWIDResetRequest(lic.id)}
                            title="Request HWID reset review"
                            className="h-8 border-white/10"
                          >
                            HWID Request
                          </Button>
                          <Button
                          size="sm"
                          variant="outline"
                          onClick={() => handleResetHWID(lic.id)}
                          title="Reset Machine Hardware lock (HWID)"
                          className="h-8 border-white/10"
                        >
                          Reset HWID
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => handleUpdateStatus(lic.id, lic.status)}
                          className={`h-8 border-white/10 ${
                            lic.status === "SUSPENDED" ? "text-emerald-400 hover:text-emerald-300" : "text-amber-400 hover:text-amber-300"
                          }`}
                        >
                          {lic.status === "SUSPENDED" ? "Unsuspend" : "Suspend"}
                        </Button>
                        {lic.status !== "BLACKLISTED" && (
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleBlacklist(lic.id)}
                            className="h-8 border-red-500/20 text-red-400 hover:bg-red-950/40 hover:text-red-300"
                            title="Blacklist this key"
                          >
                            Blacklist
                          </Button>
                        )}
                        <Button size="sm" variant="destructive" onClick={() => handleDelete(lic.id)} className="h-8 bg-red-950/40 text-red-400 border border-red-500/20">
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </Card>
      )}

      {/* Generate Keys Modal */}
      <AnimatePresence>
        {modalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
            <motion.div
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              className="bg-[#0b0f19] border border-white/10 rounded-xl p-6 max-w-md w-full space-y-4"
            >
              <div className="flex items-center justify-between pb-2 border-b border-white/5">
                <h2 className="text-xl font-bold text-white flex items-center gap-2">
                  <KeyRound className="h-5 w-5 text-red-400" />
                  <span>Bulk License Generator</span>
                </h2>
                <button onClick={() => setModalOpen(false)} className="text-gray-400 hover:text-white transition-colors">
                  <X className="h-5 w-5" />
                </button>
              </div>

              <form onSubmit={handleGenerate} className="space-y-4 pt-2">
                <div className="space-y-1">
                  <label className="text-xs text-gray-400 font-semibold uppercase">Linked Script</label>
                  <select
                    value={scriptId}
                    onChange={(e) => setScriptId(e.target.value)}
                    required
                    className="flex h-10 w-full rounded-lg border border-border/60 bg-black/40 px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-primary/50"
                  >
                    {scripts.map((sc) => (
                      <option key={sc.id} value={sc.id} className="bg-[#0b0f19]">
                        {sc.name}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-semibold uppercase">Key Type</label>
                    <select
                      value={type}
                      onChange={(e: any) => setType(e.target.value)}
                      className="flex h-10 w-full rounded-lg border border-border/60 bg-black/40 px-3 py-2 text-sm text-white focus:outline-none focus:ring-2 focus:ring-primary/50"
                    >
                      <option value="LIFETIME" className="bg-[#0b0f19]">Lifetime</option>
                      <option value="SUBSCRIPTION" className="bg-[#0b0f19]">Subscription</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs text-gray-400 font-semibold uppercase">Generation Count</label>
                    <Input
