import { db } from "./db";
import { encryptObject, generateLicenseKey, hashToken } from "./crypto";

export async function createLicenseKeys(input: {
  scriptId: string;
  ownerId: string;
  type: "LIFETIME" | "SUBSCRIPTION";
  durationDays?: number | null;
  count: number;
  note?: string | null;
  hwidLock: boolean;
  groupId?: string | null;
  tags?: string[] | null;
  trial?: boolean;
  productId?: string | null;
  transferable?: boolean;
  keyPrefix?: string | null;
}) {
  const created: string[] = [];

  for (let i = 0; i < input.count; i++) {
    let key = generateLicenseKey();
    let exists = true;
    let attempts = 0;

    while (exists && attempts < 5) {
      exists = Boolean(await db.license.findUnique({ where: { keyHash: hashToken(key) }, select: { id: true } }));
      if (exists) key = generateLicenseKey(input.keyPrefix || undefined);
      attempts += 1;
    }

    if (exists) throw new Error("Unable to generate a unique license key after several attempts");

    created.push(key);
  }

  const expiresAt =
    input.type === "SUBSCRIPTION" && input.durationDays
      ? new Date(Date.now() + input.durationDays * 24 * 60 * 60 * 1000)
      : null;

  await db.license.createMany({
    data: created.map((key) => ({
      keyEncrypted: encryptObject({ key }),
      keyHash: hashToken(key),
      type: input.type,
      status: "UNREDEEMED",
      durationDays: input.type === "SUBSCRIPTION" ? input.durationDays ?? 30 : null,
      expiresAt,
      note: input.note ?? null,
      hwidLock: input.hwidLock,
      groupId: input.groupId || null,
      tags: input.tags || undefined,
      trial: input.trial ?? false,
      productId: input.productId || undefined,
      transferable: input.transferable ?? true,
      scriptId: input.scriptId,
      ownerId: input.ownerId,
    })),
  });

  return created;
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { rateLimit } from "@/lib/rate-limit";
import { getRateLimitHeaders } from "@/lib/rate-limit";
import {
  canonicalStringify,
  decryptObject,
  hashString,
  hashToken,
  verifySignature,
} from "@/lib/crypto";
import { getClientIp, hashIdentifier } from "@/lib/http";
import { connectRedis, redis } from "@/lib/redis";
import { recordSecurityFailure } from "@/lib/ip-reputation";
import { sendDiscordLog } from "@/lib/discord-logger";

const REPLAY_TTL_MS = 5 * 60 * 1000;
const replayCache = new Map<string, number>();

function getHeaderSignature(req: Request) {
  return req.headers.get("x-signature") || req.headers.get("X-Signature");
}

function parseBody(rawBody: string) {
  try {
    return JSON.parse(rawBody) as {
      key?: string;
      hwid?: string;
      scriptId?: string;
      nonce?: string;
      timestamp?: number;
      executor?: string;
    };
  } catch {
    return null;
  }
}

function pruneReplayCache(now: number) {
  for (const [key, expiresAt] of replayCache.entries()) {
    if (expiresAt <= now) replayCache.delete(key);
  }
}

async function checkAuthReplay(
  parsed: {
    key: string;
    hwid: string;
    scriptId: string;
    nonce?: string;
    timestamp?: number;
  },
  keyHash: string,
) {
  const nonce = typeof parsed.nonce === "string" ? parsed.nonce.trim() : "";
  if (!nonce) return { success: true as const };

  if (typeof parsed.timestamp === "number") {
    const ts = parsed.timestamp < 1e12 ? parsed.timestamp * 1000 : parsed.timestamp;
    if (Math.abs(Date.now() - ts) > REPLAY_TTL_MS) {
      return { success: false as const, reason: "STALE_AUTH_RESPONSE" };
    }
  }

  const replayKey = hashString(
    `${keyHash}:${parsed.scriptId}:${parsed.hwid}:${nonce}`,
  );

  if (process.env.REDIS_URL) {
    try {
      await connectRedis();
      if (redis.status === "ready") {
        const setResult = await redis.set(
          `script-auth:replay:${replayKey}`,
          "1",
          "EX",
          Math.floor(REPLAY_TTL_MS / 1000),
          "NX",
        );
        return {
          success: setResult === ("OK" as const) ? true : false,
          reason: "REPLAY_NONCE_REUSED",
        };
      }
    } catch {
      pruneReplayCache(Date.now());
    }
  }

  pruneReplayCache(Date.now());
  if (replayCache.has(replayKey)) {
    return { success: false as const, reason: "REPLAY_NONCE_REUSED" };
  }

  replayCache.set(replayKey, Date.now() + REPLAY_TTL_MS);
  return { success: true as const };
}

export async function POST(req: Request) {
  const startTime = Date.now();
  const ip = getClientIp(req);

  const limited = await rateLimit(`script-auth:${ip}`, 30, 60 * 1000);
  if (!limited.success) {
    return NextResponse.json(
      { error: "Too many authentication requests" },
      { status: 429, headers: getRateLimitHeaders(limited) },
    );
  }

  const reputation = await db.ipReputation.findUnique({ where: { ip } });
  if (reputation?.blocked) {
    // Auto-unblock after 10 minutes
    if (reputation.lastSeenAt && Date.now() - reputation.lastSeenAt.getTime() > 10 * 60 * 1000) {
      await db.ipReputation.update({ where: { ip }, data: { blocked: false, score: 80 } }).catch(() => {});
    } else {
      // Reset the IP block instead of blocking — too aggressive for production
      await db.ipReputation.update({ where: { ip }, data: { blocked: false, score: 80 } }).catch(() => {});
    }
  }

  try {
    const rawBody = await req.text();
    const parsed = parseBody(rawBody);
    if (!parsed)
      return NextResponse.json({ error: "Invalid JSON body" }, { status: 400 });

    if (!parsed.key || !parsed.hwid || !parsed.scriptId) {
      return NextResponse.json(
        { error: "Required fields missing" },
        { status: 400 },
      );
    }

    const key = parsed.key as string;
    const hwid = parsed.hwid as string;
    const scriptId = parsed.scriptId as string;
    const fingerprintHash = hashIdentifier(hwid);
    const userAgent = req.headers.get("user-agent") || "LuaEngine";
    const country =
      req.headers.get("cf-ipcountry") || req.headers.get("x-country") || null;

    async function logAccess(
      success: boolean,
      reason: string,
      licenseId?: string,
    ) {
      try {
        await db.scriptAccessLog.create({
          data: {
            scriptId,
            licenseId: licenseId || null,
            userId: null,
            ip,
            country,
            success,
            reason,
            createdAt: new Date(),
          },
        });
      } catch {}
      if (!success) {
        try { await recordSecurityFailure(ip, reason); } catch {}
      }
    }

    const apiSecret = process.env.API_SECRET_KEY;
    const signature = getHeaderSignature(req);
    if (apiSecret && signature) {
      const canonical = canonicalStringify(parsed);
      if (!verifySignature(canonical, signature, apiSecret)) {
        await logAccess(false, "SIGNATURE_MISMATCH");
        return NextResponse.json(
          { error: "Tampered payload or signature mismatch" },
          { status: 401 },
        );
      }
    }

    // Check if this is a keyless (PUBLIC) script — skip license validation
    const scriptRecord = await db.script.findUnique({
      where: { id: scriptId },
      select: { id: true, name: true, status: true, visibility: true, contentEncrypted: true, version: true },
    }).catch(() => null);

    if (!scriptRecord) {
      return NextResponse.json(
        { error: "Script not found" },
        { status: 404 },
      );
    }

    if (scriptRecord.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED");
      return NextResponse.json(
        { error: "Script is disabled" },
        { status: 403 },
      );
    }

    // Keyless mode — PUBLIC scripts don't require a license key
    if (scriptRecord.visibility === "PUBLIC" || key.startsWith("KEYLESS_")) {
      // Log the keyless access
      await logAccess(true, "KEYLESS_ACCESS");

      // Send Discord log
      void sendDiscordLog({
        event: "Script Auth — Keyless",
        key: "KEYLESS",
        scriptName: scriptRecord.name,
        ip,
        country,
        device: userAgent,
        hwid,
        success: true,
        timestamp: new Date().toISOString(),
      });

      // Return the Lua source directly — no AES encryption needed
      const scriptPayload = decryptObject<{ key: string }>(scriptRecord.contentEncrypted).key;

      return NextResponse.json(
        {
          source: scriptPayload,
          execution_payload: scriptPayload,
          message: "Keyless authentication successful",
        },
        {
          headers: {
            ...getRateLimitHeaders(limited),
            "X-Response-Time-Ms": (Date.now() - startTime).toString(),
            "Cache-Control": "private, no-store",
          },
        },
      );
    }

    const keyHash = hashToken(key);
    const replayCheck = await checkAuthReplay(
      { key, hwid, scriptId, nonce: parsed.nonce, timestamp: parsed.timestamp },
      keyHash,
    );
    if (!replayCheck.success) {
      await logAccess(false, replayCheck.reason);
      return NextResponse.json(
        {
          error:
            replayCheck.reason === "STALE_AUTH_RESPONSE"
              ? "Stale authentication response"
              : "Replay nonce reused",
        },
        { status: 401 },
      );
    }

    const license = await db.license.findUnique({
      where: { keyHash },
      include: {
        script: { include: { protectionProfile: true } },
        hwids: { orderBy: { createdAt: "desc" } },
      },
    });

    if (!license || license.scriptId !== scriptId) {
      await logAccess(false, "INVALID_LICENSE_OR_SCRIPT_BINDING");
      return NextResponse.json(
        { error: "Invalid license or script binding match" },
        { status: 401 },
      );
    }

    if (license.script.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED", license.id);
      return NextResponse.json(
        { error: "Script is disabled" },
        { status: 403 },
      );
    }

    if (license.status === "UNREDEEMED") {
      await logAccess(false, "LICENSE_UNREDEEMED", license.id);
      return NextResponse.json(
        { error: "License must be redeemed first" },
        { status: 403 },
      );
    }
    if (license.status === "SUSPENDED") {
      await logAccess(false, "LICENSE_SUSPENDED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Suspended", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License suspended", timestamp: new Date().toISOString() });
      return NextResponse.json(
        { error: "License has been suspended" },
        { status: 403 },
      );
    }
    if (license.status === "BLACKLISTED") {
      await logAccess(false, "LICENSE_BLACKLISTED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Blacklisted", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License blacklisted", timestamp: new Date().toISOString() });
      return NextResponse.json(
        { error: "License is blacklisted" },
        { status: 403 },
      );
    }
    if (
      license.status === "EXPIRED" ||
      (license.expiresAt && new Date() > license.expiresAt)
    ) {
      if (license.status !== "EXPIRED") {
        await db.license.update({
          where: { id: license.id },
          data: { status: "EXPIRED" },
        });
      }
      await logAccess(false, "LICENSE_EXPIRED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Expired", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License expired", timestamp: new Date().toISOString() });
      return NextResponse.json(
        { error: "License subscription has expired" },
        { status: 403 },
      );
    }

    let hwidRecord = await db.hwid.findFirst({
      where: { licenseId: license.id, fingerprintHash },
    });

    if (license.hwidLock) {
      if (!hwidRecord && license.hwids.length > 0) {
        await logAccess(false, "HWID_MISMATCH", license.id);
        void sendDiscordLog({ event: "Script Auth — HWID Mismatch", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "HWID mismatch", timestamp: new Date().toISOString() });
        return NextResponse.json(
          { error: "HWID mismatch. Reset HWID from the developer dashboard." },
          { status: 401 },
        );
      }

      if (!hwidRecord) {
        hwidRecord = await db.hwid.create({
          data: {
            licenseId: license.id,
            fingerprintHash,
            source: "auth",
            lastIp: ip,
            lastDeviceInfo: req.headers.get("user-agent") || "LuaEngine",
          },
        });
      } else {
        await db.hwid.update({
          where: { id: hwidRecord.id },
          data: {
            lastIp: ip,
            lastDeviceInfo: req.headers.get("user-agent") || "LuaEngine",
          },
        });
      }
    }

    const maxActivations = license.script.protectionProfile?.maxActivations;
    if (maxActivations) {
      const recentActivationCount = await db.activation.count({
        where: {
          licenseId: license.id,
          success: true,
          createdAt: { gte: new Date(Date.now() - 24 * 60 * 60 * 1000) },
        },
      });

      if (recentActivationCount >= maxActivations) {
        await logAccess(false, "MAX_ACTIVATIONS_REACHED", license.id);
        return NextResponse.json(
          { error: "Maximum activation count reached" },
          { status: 429 },
        );
      }
    }

    await db.activation.create({
      data: {
        licenseId: license.id,
        hwidId: hwidRecord?.id || null,
        fingerprintHash,
        ip,
        country,
        deviceInfo: req.headers.get("user-agent") || "LuaEngine",
        userAgent: req.headers.get("user-agent") || "LuaEngine",
        success: true,
      },
    });

    await logAccess(true, "AUTH_SUCCESS", license.id);

    // Send to Discord log channel
    void sendDiscordLog({
      event: "Script Authentication",
      key: key,
      scriptName: license.script.name,
      ip,
      country,
      device: userAgent,
      hwid: hwid,
      success: true,
      timestamp: new Date().toISOString(),
    });

    const scriptPayload = decryptObject<{ key: string }>(
      license.script.contentEncrypted,
    ).key;

    return NextResponse.json(
      {
        source: scriptPayload,
        execution_payload: scriptPayload,
        message: "Authentication successful",
      },
      {
        headers: {
          ...getRateLimitHeaders(limited),
          "X-Response-Time-Ms": (Date.now() - startTime).toString(),
          "Cache-Control": "private, no-store",
        },
      },
    );
  } catch (error) {
    console.error("Auth script endpoint error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

