import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { decryptObject } from "@/lib/crypto";
import { getAuthenticatedUser, getJson, type SessionUser } from "@/lib/http";
import { canManageResource } from "@/lib/team-permissions";
import { z } from "zod";

const updateSchema = z.object({
  status: z
    .enum(["UNREDEEMED", "ACTIVE", "SUSPENDED", "EXPIRED", "BLACKLISTED"])
    .optional(),
  note: z.string().max(200).optional().nullable(),
  hwidLock: z.boolean().optional(),
  blacklistReason: z.string().max(500).optional().nullable(),
  groupId: z.string().uuid().optional().nullable(),
  tags: z.array(z.string().max(40)).max(20).optional(),
  trial: z.boolean().optional(),
  productId: z.string().max(80).optional().nullable(),
  transferable: z.boolean().optional(),
});

function sanitizeLicense(license: any) {
  return {
    ...license,
    key: decryptObject<{ key: string }>(license.keyEncrypted).key,
    keyEncrypted: undefined,
    keyHash: undefined,
  };
}

async function canManage(
  user: SessionUser,
  license: { ownerId: string; scriptId: string },
) {
  const script = await db.script.findUnique({
    where: { id: license.scriptId },
    select: { ownerId: true, teamId: true },
  });
  return canManageResource(user, {
    ownerId: license.ownerId,
    teamId: script?.teamId || null,
  });
}

export async function PUT(
  req: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  const user = await getAuthenticatedUser(req);
  if (!user || !["ADMIN", "DEVELOPER", "SELLER"].includes(user.role))
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { id } = await params;
  const license = await db.license.findUnique({ where: { id } });
  if (!license)
    return NextResponse.json({ error: "License not found" }, { status: 404 });
  if (!(await canManage(user, license)))
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  try {
    const body = updateSchema.safeParse(await getJson(req));
    if (!body.success)
      return NextResponse.json(
        {
          error: "Invalid license update request",
          details: body.error.flatten(),
        },
        { status: 400 },
      );

    const data = body.data;
    const updated = await db.license.update({
      where: { id },
      data: {
        status: data.status,
        note: data.note,
        hwidLock: data.hwidLock,
        blacklistReason:
          data.status === "BLACKLISTED"
            ? data.blacklistReason || "No reason provided"
            : null,
        groupId: data.groupId,
        tags: data.tags || undefined,
        trial: data.trial,
        productId: data.productId,
        transferable: data.transferable,
      },
    });

    await createAuditLog(
      user.id,
      "LICENSE_UPDATE",
      { licenseId: id, status: data.status },
      undefined,
      req.headers.get("user-agent") || undefined,
      "License",
      id,
    );
    return NextResponse.json({
      message: "License updated successfully",
      license: sanitizeLicense(updated),
    });
  } catch (error) {
    console.error("PUT License Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

export async function DELETE(
  req: Request,
  { params }: { params: Promise<{ id: string }> },
) {
  const user = await getAuthenticatedUser(req);
  if (!user || !["ADMIN", "DEVELOPER", "SELLER"].includes(user.role))
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { id } = await params;
  const license = await db.license.findUnique({ where: { id } });
  if (!license)
    return NextResponse.json({ error: "License not found" }, { status: 404 });
  if (!(await canManage(user, license)))
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  await db.license.delete({ where: { id } });
  await createAuditLog(
    user.id,
    "LICENSE_DELETE",
    { licenseId: id },
    undefined,
    req.headers.get("user-agent") || undefined,
    "License",
    id,
  );

  return NextResponse.json({ message: "License key deleted successfully" });
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { dispatchWebhook } from "@/lib/webhooks";
import { getClientIp, getJson, hashIdentifier, rateLimit } from "@/lib/http";
import { hashToken } from "@/lib/crypto";
import { z } from "zod";

const redeemSchema = z.object({
  key: z.string().min(8).max(64),
  redeemedBy: z.string().min(2).max(128),
  hwid: z.string().min(8).max(512).optional(),
});

export async function POST(req: Request) {
  const ip = getClientIp(req);
  const limited = await rateLimit(`license:redeem:${ip}`, 10, 60 * 1000);
  if (!limited.success) return NextResponse.json({ error: "Too many redemption attempts" }, { status: 429, headers: { "X-RateLimit-Reset": limited.reset.toString() } });

  try {
    const body = redeemSchema.safeParse(await getJson(req));
    if (!body.success) return NextResponse.json({ error: "License key and user identifier are required", details: body.error.flatten() }, { status: 400 });

    const { key, redeemedBy, hwid } = body.data;
    const keyHash = hashToken(key);
    const license = await db.license.findUnique({
      where: { keyHash },
      include: { script: true },
    });

    if (!license) return NextResponse.json({ error: "License key does not exist" }, { status: 404 });
    if (license.status !== "UNREDEEMED") return NextResponse.json({ error: `License key is already redeemed (Status: ${license.status})` }, { status: 400 });

    let expiresAt: Date | null = null;
    if (license.type === "SUBSCRIPTION" && license.durationDays) {
      expiresAt = new Date(Date.now() + license.durationDays * 24 * 60 * 60 * 1000);
    }

    const updated = await db.$transaction(async (tx) => {
      const licenseUpdate = await tx.license.update({
        where: { id: license.id },
        data: {
          status: "ACTIVE",
          redeemedBy,
          redeemedAt: new Date(),
          expiresAt,
        },
      });

      if (hwid && license.hwidLock) {
        await tx.hwid.create({
          data: {
            licenseId: license.id,
            fingerprintHash: hashIdentifier(hwid),
            source: "redeem",
            lastIp: ip,
          },
        }).catch(() => undefined);
      }

      return licenseUpdate;
    });

    await createAuditLog(license.ownerId, "LICENSE_REDEEM", { licenseId: license.id, redeemedBy, expiresAt }, ip, req.headers.get("user-agent") || undefined, "License", license.id);
    void dispatchWebhook(license.ownerId, "key.redeemed", {
      licenseId: license.id,
      redeemedBy,
      type: license.type,
      expiresAt: expiresAt?.toISOString() || "Lifetime",
      scriptName: license.script.name,
    });

    return NextResponse.json({ message: "License key successfully activated and redeemed!", license: updated });
  } catch (error) {
    console.error("Redeem License Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { dispatchWebhook } from "@/lib/webhooks";
import { getClientIp, getAuthenticatedUser, rateLimit } from "@/lib/http";

async function canManage(user: { id: string; role: string }, license: { ownerId: string }) {
  return user.role === "ADMIN" || license.ownerId === user.id;
}

export async function POST(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const user = await getAuthenticatedUser(req);
  if (!user || !["ADMIN", "DEVELOPER", "SELLER"].includes(user.role)) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`license:hwid-reset:${user.id}`, 5, 60 * 60 * 1000);
  if (!limited.success) return NextResponse.json({ error: "Too many HWID reset attempts" }, { status: 429 });

  const { id } = await params;
  const license = await db.license.findUnique({ where: { id } });
  if (!license) return NextResponse.json({ error: "License not found" }, { status: 404 });
  if (!(await canManage(user, license))) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  if (license.hwidResetCount >= license.hwidResetLimit && user.role !== "ADMIN") {
    return NextResponse.json({ error: "HWID reset limit reached for this license key" }, { status: 400 });
  }

  const ip = getClientIp(req);
  await db.$transaction([
    db.hwid.deleteMany({ where: { licenseId: id } }),
    db.license.update({ where: { id }, data: { hwidResetCount: { increment: 1 } } }),
  ]);

  await createAuditLog(user.id, "LICENSE_HWID_RESET", { licenseId: id, currentResetCount: license.hwidResetCount + 1 }, ip, req.headers.get("user-agent") || undefined, "License", id);
  void dispatchWebhook(user.id, "hwid.reset", { licenseId: id, resetCount: license.hwidResetCount + 1 });

  return NextResponse.json({ message: "HWID cleared successfully. Ready for next machine activation." });
}

