        body: JSON.stringify({
          scriptId, type, durationDays, count, note, hwidLock,
          tags: tags.split(",").map((tag) => tag.trim()).filter(Boolean),
          trial, productId: productId || null, transferable,
          keyPrefix: keyPrefix || undefined,
