## 4. `src/lib/crypto.ts` — `generateLicenseKey` function (plus its helper)

```ts
export function randomLicenseSegment(bytes = 5): string {
  const alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let output = "";
  const random = crypto.randomBytes(bytes);
  for (let i = 0; i < bytes; i++) {
    output += alphabet[random[i] % alphabet.length];
  }
  return output;
}

export function generateLicenseKey(prefix = "LUA"): string {
  return `${prefix}-${randomLicenseSegment(5)}-${randomLicenseSegment(5)}-${randomLicenseSegment(5)}`;
}
```

> Note: the alphabet `ABCDEFGHJKLMNPQRSTUVWXYZ23456789` deliberately omits ambiguous characters (no `I`, `O`, `0`, `1`). Key format: `LUA-XXXXX-XXXXX-XXXXX` (each segment 5 chars from 32-char alphabet).

