import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { getAuthenticatedUser, getJson } from "@/lib/http";
import { z } from "zod";

const reviewSchema = z.object({ status: z.enum(["ACCEPTED", "DECLINED"]), note: z.string().max(500).optional().nullable() });

export async function PATCH(req: Request, { params }: { params: Promise<{ id: string }> }) {
  const user = await getAuthenticatedUser(req);
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { id } = await params;
  const request = await db.licenseTransferRequest.findUnique({ where: { id } });
  if (!request) return NextResponse.json({ error: "Transfer request not found" }, { status: 404 });
  const license = await db.license.findUnique({ where: { id: request.licenseId }, select: { ownerId: true } });
  if (!license) return NextResponse.json({ error: "License not found" }, { status: 404 });
  if (request.status !== "PENDING") return NextResponse.json({ error: "Transfer request already handled" }, { status: 400 });
  if (license.ownerId !== user.id && user.role !== "ADMIN") return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const body = reviewSchema.safeParse(await getJson(req));
  if (!body.success) return NextResponse.json({ error: "Invalid review", details: body.error.flatten() }, { status: 400 });

  let updated;
  if (body.data.status === "ACCEPTED") {
    const recipient = await db.user.findUnique({ where: { email: request.toUserEmail } });
    if (!recipient) {
      updated = await db.licenseTransferRequest.update({ where: { id }, data: { status: "DECLINED", note: body.data.note || "Recipient not found" } });
    } else {
      updated = await db.$transaction([
        db.license.update({ where: { id: request.licenseId }, data: { ownerId: recipient.id, redeemedBy: recipient.id } }),
        db.licenseTransferRequest.update({ where: { id }, data: { status: "ACCEPTED", note: body.data.note } }),
      ]).then(([, row]) => row);
    }
  } else {
    updated = await db.licenseTransferRequest.update({ where: { id }, data: { status: "DECLINED", note: body.data.note } });
  }

  await createAuditLog(user.id, "LICENSE_TRANSFER_REVIEWED", { transferId: id, status: updated.status }, undefined, req.headers.get("user-agent") || undefined, "License", request.licenseId);
  return NextResponse.json({ request: updated });
}
